import { Component, OnInit } from '@angular/core';
import { CommonModule, CurrencyPipe, DatePipe } from '@angular/common';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatSelectModule } from '@angular/material/select';
import { MatChipsModule } from '@angular/material/chips';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { InvoiceService } from '../../core/services/invoice.service';
import { Invoice } from '../../models/invoice.model';

@Component({
  selector: 'app-alerts',
  standalone: true,
  imports: [CommonModule, RouterModule, CurrencyPipe, DatePipe, FormsModule,
    MatButtonModule, MatIconModule, MatSelectModule, MatChipsModule],
  templateUrl: './alerts.component.html',
  styleUrls: ['./alerts.component.scss']
})
export class AlertsComponent implements OnInit {
  allAlerts: Invoice[] = [];
  filtered: Invoice[] = [];
  filterLevel: string = 'ALL';

  constructor(private invoiceService: InvoiceService) {}

  ngOnInit(): void {
    this.invoiceService.getOverdue().subscribe({
      next: (data) => { this.allAlerts = data; this.applyFilter(); },
      error: () => { this.allAlerts = MOCK_ALERTS; this.applyFilter(); }
    });
  }

  applyFilter(): void {
    this.filtered = this.filterLevel === 'ALL'
      ? this.allAlerts
      : this.allAlerts.filter(a => a.riskLevel === this.filterLevel);
  }

  getRiskClass(score: number): string {
    if (score >= 70) return 'high';
    if (score >= 40) return 'medium';
    return 'low';
  }

  get highCount()   { return this.allAlerts.filter(a => a.riskLevel === 'HIGH').length; }
  get mediumCount() { return this.allAlerts.filter(a => a.riskLevel === 'MEDIUM').length; }
}

